// ---- Why ViewModel? ----
// ViewModel survives configuration changes (screen rotation)

// ---- Without ViewModel (state lost on rotation) ----
@Composable
fun WithoutViewModel() {
    var count by remember { mutableStateOf(0) }

    // Problem: Count resets to 0 on screen rotation!
    Column {
        Text("Count: $count")
        Button(onClick = { count++ }) {
            Text("Increment")
        }
    }
}

// ---- With ViewModel (state persists) ----
// 1. Add dependencies:
// implementation("androidx.lifecycle:lifecycle-viewmodel-compose:2.8.0")

// 2. Create ViewModel
class CounterViewModel : ViewModel() {
    private val _count = mutableStateOf(0)
    val count: State<Int> = _count

    fun increment() {
        _count.value++
    }

    fun decrement() {
        _count.value--
    }

    fun reset() {
        _count.value = 0
    }
}

// 3. Use ViewModel in Composable
@Composable
fun WithViewModel() {
    val viewModel: CounterViewModel = viewModel()
    val count by viewModel.count

    Column(
        modifier = Modifier
            .fillMaxSize()
            .padding(16.dp),
        horizontalAlignment = Alignment.CenterHorizontally,
        verticalArrangement = Arrangement.spacedBy(16.dp)
    ) {
        Text(
            text = "Count: $count",
            style = MaterialTheme.typography.headlineLarge
        )

        Row(
            horizontalArrangement = Arrangement.spacedBy(8.dp)
        ) {
            Button(onClick = { viewModel.decrement() }) {
                Text("-")
            }
            Button(onClick = { viewModel.increment() }) {
                Text("+")
            }
        }

        Button(onClick = { viewModel.reset() }) {
            Text("Reset")
        }

        // ---- ViewModel lifecycle ----
        // ViewModel survives screen rotation!
        // ViewModel is cleared when the activity is finished
    }
}

// ---- ViewModel with initial state ----
class GameViewModel : ViewModel() {
    private val _score = mutableStateOf(0)
    val score: State<Int> = _score

    private val _lives = mutableStateOf(3)
    val lives: State<Int> = _lives

    fun addScore(points: Int) {
        _score.value += points
    }

    fun loseLife() {
        if (_lives.value > 0) {
            _lives.value--
        }
    }

    fun resetGame() {
        _score.value = 0
        _lives.value = 3
    }
}

// ---- ViewModel with saved state ----
class SavedStateViewModel(handle: SavedStateHandle) : ViewModel() {
    private val _count = handle.getStateFlow("count", 0)
    val count: StateFlow<Int> = _count

    fun increment() {
        // SavedStateHandle automatically saves the state
    }
}

